// Extract payload from webhook
const payload = $input.first().json.body || $input.first().json;

const submissionId = payload.submission_id;
const orgId = payload.org_id;
const listingId = payload.listing_id;
const readinessScore = payload.readiness_score;
const channels = Array.isArray(payload.channels) ? payload.channels : [];
const optimalPrice = payload.optimal_price;
const firedAt = payload.fired_at || new Date().toISOString();

// Format price
const priceStr = optimalPrice 
  ? new Intl.NumberFormat('pt-PT', { style: 'currency', currency: 'EUR', maximumFractionDigits: 0 }).format(optimalPrice)
  : 'Preço não definido';

// Build notification messages
const emailSubject = `[AG] Nova Propriedade LIVE — ${listingId.slice(0,8)}`;
const emailBody = `
Nova propriedade publicada automaticamente pelo Property AI Engine.

Submission ID: ${submissionId}
Listing ID: ${listingId}
Readiness Score: ${readinessScore}/100
Preço Recomendado: ${priceStr}
Canais: ${channels.join(', ')}
Publicado: ${new Date(firedAt).toLocaleString('pt-PT')}

Ver no dashboard: https://www.agencygroup.pt/dashboard/properties/${submissionId}
`.trim();

const slackMsg = `🏠 *Nova propriedade LIVE* — Score ${readinessScore}/100\n> ${priceStr} | ${channels.length} canais\n<https://www.agencygroup.pt/dashboard/properties/${submissionId}|Ver detalhes →>`;

return [{ json: { submissionId, listingId, readinessScore, priceStr, channels, emailSubject, emailBody, slackMsg, firedAt } }];
